31	        respond({
32	          jsonrpc: '2.0',
33	          error: {
34	            code: -32000,
35	            message: e.message,
36	            data: {
37	              stack: e.stack,
38	            },
39	          },
40	          id: json.id,
41	        })
42	      }
43	    }
