 */

/** Wraps a block of text in a TypeScript interface declaration. */
export function interfaceDeclaration(name: string, fields: string): string {
  return `export interface ${name} {\n${fields}}\n`
}

/** Produces a single interface field line with proper indentation. */
export function fieldLine(name: string, tsType: string, optional: boolean): string {
  const optionalMark = optional ? '?' : ''
  return `  ${name}${optionalMark}: ${tsType}\n`
}

/** Wraps content in a generic `Promise<T>` type string. */
export function promiseOf(inner: string): string {
  return `Promise<${inner}>`
}

/** Produces a typed method signature string (no body). */
export function methodSignature(name: string, params: string, returnType: string): string {
  return `  ${name}(${params}): ${returnType}`
}

/** Generates a file header comment. */
export function fileHeader(): string {
  return [
    '// -------------------------------------------------------',
    '// Prisma REST Client — auto-generated, do not edit',
    '// -------------------------------------------------------',
    '',
    '',
  ].join('\n')
}

/** Joins multiple code blocks with blank-line separators. */
