import path from 'node:path'
import fs from 'node:fs'

import type { Document, Field, Model } from '@prisma/dmmf'

import {
  fileHeader,
  configInterface,
  interfaceDeclaration,
  fieldLine,
  joinBlocks,
  classDeclaration,
  methodSignature,
  promiseOf,
} from './template'

/**
 * Map a Prisma scalar type name to its TypeScript equivalent.
 * Relation/object fields are mapped to `any` as a reasonable
 * fallback — the generated REST client is concerned with the
 * JSON shape returned by an HTTP API, not nested Prisma types.
 */
function scalarToTs(field: Field): string {
  if (field.kind === 'object') {
    return field.isList ? 'any[]' : 'any'
  }

  if (field.kind === 'enum') {
    return 'string'
  }

  switch (field.type) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'any'
    case 'Bytes':
      return 'Buffer'
    default:
      return 'any'
  }
}

/** Determine the TypeScript type string for a DMMF field, accounting for lists. */
function fieldTsType(field: Field): string {
  const base = scalarToTs(field)
  if (field.isList) {
    // `scalarToTs` already appends `[]` for object lists
    return field.kind === 'object' ? base : `${base}[]`
  }
  return base
}

/** Generate a TypeScript interface for a single Prisma model. */
function generateModelInterface(model: Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => fieldLine(f.name, fieldTsType(f), !f.isRequired))
    .join('')

  return interfaceDeclaration(model.name, fields)
}

/**
 * Generate a `CreateInput` type that omits auto-generated fields
 * (id fields, `@updatedAt`, readonly fields).
 */
function generateCreateInput(model: Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object' && !f.isReadOnly && !f.isGenerated && !f.isUpdatedAt)
    .map((f) => {
      const optional = !f.isRequired || f.hasDefaultValue || f.isId
      return fieldLine(f.name, fieldTsType(f), optional)
    })
    .join('')

  return interfaceDeclaration(`${model.name}CreateInput`, fields)
}

/** Generate an `UpdateInput` type where every field is optional. */
function generateUpdateInput(model: Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object' && !f.isReadOnly && !f.isGenerated && !f.isUpdatedAt)
    .map((f) => fieldLine(f.name, fieldTsType(f), true))
    .join('')

  return interfaceDeclaration(`${model.name}UpdateInput`, fields)
}

/** Generate a `WhereUniqueInput` type based on the model's unique / id fields. */
function generateWhereUniqueInput(model: Model): string {
  const idFields = model.fields.filter((f) => f.isId || f.isUnique)
  const fields = idFields.map((f) => fieldLine(f.name, fieldTsType(f), false)).join('')

  return interfaceDeclaration(`${model.name}WhereUniqueInput`, fields)
}

/** Lowercase the first character of a string. */
function lcFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}

/**
 * Generate the CRUD delegate class for a single model.
 *
 * Each delegate exposes `findMany`, `findUnique`, `create`, `update`, and
 * `delete` methods that are properly typed with the model's interfaces.
 */
function generateModelDelegate(model: Model): string {
  const name = model.name
  const resource = lcFirst(name)
  const lines: string[] = []

  lines.push(`export class ${name}Delegate {`)
  lines.push('  #baseUrl: string')
  lines.push('  #headers: Record<string, string>')
  lines.push('')
  lines.push('  constructor(baseUrl: string, headers: Record<string, string>) {')
  lines.push('    this.#baseUrl = baseUrl')
  lines.push('    this.#headers = headers')
  lines.push('  }')
  lines.push('')

  // ── findMany ──
  lines.push(`  ${methodSignature('findMany', '', promiseOf(`${name}[]`))} {`)
  lines.push(`    return this.#request<${name}[]>('GET', '/${resource}')`)
  lines.push('  }')
  lines.push('')

  // ── findUnique ──
  lines.push(`  ${methodSignature('findUnique', `where: ${name}WhereUniqueInput`, promiseOf(`${name} | null`))} {`)
  lines.push(`    const id = ${buildIdAccessor(model)}`)
  lines.push(`    return this.#request<${name} | null>('GET', \`/${resource}/\${id}\`)`)
  lines.push('  }')
  lines.push('')

  // ── create ──
  lines.push(`  ${methodSignature('create', `data: ${name}CreateInput`, promiseOf(name))} {`)
  lines.push(`    return this.#request<${name}>('POST', '/${resource}', data)`)
  lines.push('  }')
  lines.push('')

  // ── update ──
  lines.push(
    `  ${methodSignature('update', `where: ${name}WhereUniqueInput, data: ${name}UpdateInput`, promiseOf(name))} {`,
  )
  lines.push(`    const id = ${buildIdAccessor(model)}`)
  lines.push(`    return this.#request<${name}>('PATCH', \`/${resource}/\${id}\`, data)`)
  lines.push('  }')
  lines.push('')

  // ── delete ──
  lines.push(`  ${methodSignature('delete', `where: ${name}WhereUniqueInput`, promiseOf(name))} {`)
  lines.push(`    const id = ${buildIdAccessor(model)}`)
  lines.push(`    return this.#request<${name}>('DELETE', \`/${resource}/\${id}\`)`)
  lines.push('  }')
  lines.push('')

  // ── #request helper ──
  lines.push('  async #request<T>(method: string, path: string, body?: unknown): Promise<T> {')
  lines.push('    const response = await fetch(`${this.#baseUrl}${path}`, {')
  lines.push('      method,')
  lines.push("      headers: { 'Content-Type': 'application/json', ...this.#headers },")
  lines.push('      body: body ? JSON.stringify(body) : undefined,')
  lines.push('    })')
  lines.push('    if (!response.ok) {')
  lines.push('      throw new Error(`REST client request failed: ${method} ${path} — ${response.status}`)')
  lines.push('    }')
  lines.push('    return response.json() as Promise<T>')
  lines.push('  }')

  lines.push('}')
  return lines.join('\n')
}

/**
 * Build the expression that extracts the unique identifier from a
 * `WhereUniqueInput` object.  Falls back to `Object.values(where)[0]`
 * when the model has no explicit `@id` / `@unique` field.
 */
function buildIdAccessor(model: Model): string {
  const idField = model.fields.find((f) => f.isId)
  if (idField) {
    return `where.${idField.name}`
  }
  const uniqueField = model.fields.find((f) => f.isUnique)
  if (uniqueField) {
    return `where.${uniqueField.name}`
  }
  return 'Object.values(where)[0]'
}

/** Generate the top-level `RestClient` class that aggregates all model delegates. */
function generateClientClass(models: readonly Model[]): string {
  const lines: string[] = []

  for (const model of models) {
    const prop = lcFirst(model.name)
    lines.push(`  readonly ${prop}: ${model.name}Delegate`)
  }

  lines.push('')
  lines.push('  constructor(config: RestClientConfig) {')
  lines.push("    const baseUrl = config.baseUrl.replace(/\\/+$/, '')")
  lines.push("    const headers = config.headers ?? {}")

  for (const model of models) {
    const prop = lcFirst(model.name)
    lines.push(`    this.${prop} = new ${model.name}Delegate(baseUrl, headers)`)
  }

  lines.push('  }')

  return classDeclaration('RestClient', lines.join('\n'))
}

/** Main entry point: generate the full `rest-client.ts` source from a DMMF document. */
export function generate(dmmf: Document): string {
  const models = dmmf.datamodel.models

  const blocks: string[] = [fileHeader()]

  // Config interface
  blocks.push(configInterface())

  // Per-model types + delegate classes
  for (const model of models) {
    blocks.push(generateModelInterface(model))
    blocks.push(generateCreateInput(model))
    blocks.push(generateUpdateInput(model))
    blocks.push(generateWhereUniqueInput(model))
    blocks.push(generateModelDelegate(model))
  }

  // Top-level client class
  blocks.push(generateClientClass(models))

  return joinBlocks(blocks)
}

/**
 * Write the generated REST client to disk.
 *
 * @param dmmf    The DMMF document parsed from the Prisma schema.
 * @param outputDir  The directory to write `rest-client.ts` into.
 */
export function generateRestClient(dmmf: Document, outputDir: string): void {
  fs.mkdirSync(outputDir, { recursive: true })
  const content = generate(dmmf)
  const outputPath = path.join(outputDir, 'rest-client.ts')
  fs.writeFileSync(outputPath, content, 'utf-8')
}

