    const output = generate(minimalDmmf)
    // authorId on Post is readOnly — should not appear in CreateInput
    const postCreateBlock = output.slice(
      output.indexOf('export interface PostCreateInput {'),
      output.indexOf('export interface PostUpdateInput'),
    )
    expect(postCreateBlock).not.toContain('authorId')
  })
})

